import { z } from 'zod'

/**
 * Semver version string (loose: allows common formats like "1.0.0", "0.1.0-beta.1")
 */
const SemverSchema = z
  .string()
  .regex(
    /^\d+\.\d+\.\d+(?:-[a-zA-Z0-9]+(?:\.[a-zA-Z0-9]+)*)?(?:\+[a-zA-Z0-9]+(?:\.[a-zA-Z0-9]+)*)?$/,
    'Invalid semver version',
  )

/**
 * Plugin name: lowercase, dots, hyphens, and digits.
 * Must start with a letter. Examples: "myndra.builtin.notes", "my-plugin"
 */
const PluginNameSchema = z
  .string()
  .regex(
    /^[a-z][a-z0-9._-]*$/,
    'Plugin name must start with a lowercase letter and contain only lowercase letters, digits, dots, hyphens, and underscores',
  )

/**
 * Permission declaration — colon-delimited scope:access string.
 * Examples: "filesystem:read", "filesystem:write"
 */
export const PermissionSchema = z
  .string()
  .regex(
    /^[a-z][a-z0-9-]*:[a-z][a-z0-9-]*$/,
    'Permission must be in "scope:access" format (e.g. "filesystem:read")',
  )

/**
 * Grammar configuration for tree-sitter file parsing.
 */
export const GrammarConfigSchema = z.object({
  fileExtensions: z.array(z.string().min(1)).min(1),
  wasmPath: z.string().min(1),
  languageName: z.string().min(1),
})

/**
 * Plugin category — determines runtime trust and capability boundaries.
 *
 * - product-core: Ships with the app, essential for basic functionality
 * - product-internal: Ships with the app, product features using the plugin system
 * - reference-example: In-repo examples intended as external reference templates
 * - third-party: External plugins (default for all plugins without explicit category)
 */
export const PluginCategorySchema = z.enum([
  'product-core',
  'product-internal',
  'reference-example',
  'third-party',
])

/**
 * Canonical plugin manifest schema.
 *
 * Unknown fields are stripped during parsing.
 * See `parseManifest` in `./parser.ts` for the recommended entry point.
 */
export const PluginManifestSchema = z
  .object({
    /** Unique plugin identifier */
    name: PluginNameSchema,

    /** Semantic version */
    version: SemverSchema,

    /** Entry point file, relative to the manifest directory */
    entry: z.string().min(1),

    /** Short human-readable description */
    description: z.string().optional(),

    /** Human-readable display name */
    displayName: z.string().optional(),

    /** Author name or organization */
    author: z.string().optional(),

    /** Homepage URL */
    homepage: z.string().url().optional(),

    /**
     * Semver range the host engine must satisfy for this plugin to activate.
     * Parsed by `semver.satisfies()`. When omitted the plugin is assumed compatible.
     */
    engine: z.string().optional(),

    /** Declared permissions the plugin requires */
    permissions: z.array(PermissionSchema).optional(),

    /** Declared capabilities the plugin provides */
    capabilities: z.array(z.string().min(1)).optional(),

    /** Tree-sitter grammar configuration */
    grammar: GrammarConfigSchema.optional(),

    /**
     * Whether to persist this plugin's session layers to sessions.json.
     * Transient layers are never persisted regardless of this flag.
     * @default false
     */
    persistSessionLayers: z.boolean().default(false),

    /**
     * Plugin category for runtime trust and capability boundaries.
     * @default 'third-party'
     */
    category: PluginCategorySchema.default('third-party'),

    /**
     * Hard dependencies on other plugins.
     * Keys are plugin IDs, values are semver range constraints
     * (version matching is deferred — currently only presence is checked).
     */
    dependencies: z.record(PluginNameSchema, z.string()).optional(),

    /** Static contribution declarations */
    contributes: z.record(z.string(), z.unknown()).optional(),

    /** Edge kinds this plugin contributes to the graph */
    edgeKinds: z
      .array(
        z.object({
          kind: z.string().min(1),
          label: z.string().optional(),
          color: z
            .string()
            .regex(/^#[0-9a-fA-F]{6}$/)
            .optional(),
          description: z.string().optional(),
        }),
      )
      .optional(),
  })
  .strip()
