import z from 'zod'
import { createId } from '../../utils/idUtils'
import { EdgeDisplayDataSchema, HexColorSchema } from '../../lib/sigma/schemas'
import { SerializedEdgeSchema } from '../../lib/graphology/schemas'
import type { MyndlinkTransientKeys } from './types'
import { MYNDLINK_PRESETS } from './defaults'

export const MyndlinkKeySchema = z.string().min(1)

export const MyndlinkCoreKindSchema = z.enum(['reference', 'hierarchy'])

export const MyndlinkKindSchema = MyndlinkCoreKindSchema.or(z.string().min(1))

export const MyndlinkTypesSchema = z.enum(['rectangle', 'arrow', 'line'])

export const MyndlinkDirectionSchema = z.enum(['outgoing', 'incoming', 'bidirectional'])

const MyndlinkAttributesBaseSchema = EdgeDisplayDataSchema.extend({
  kind: MyndlinkKindSchema.default(MYNDLINK_PRESETS.fallback.kind),
  type: MyndlinkTypesSchema.default(MYNDLINK_PRESETS.fallback.type),
  label: z.string().nullable().default(null),
  size: z.number().positive().default(MYNDLINK_PRESETS.fallback.size),
  color: HexColorSchema.default(MYNDLINK_PRESETS.fallback.color),
})

const MyndlinkAttributesReferenceSchema = MyndlinkAttributesBaseSchema.extend({
  kind: z.literal(MYNDLINK_PRESETS.reference.kind).default(MYNDLINK_PRESETS.reference.kind),
  type: MyndlinkTypesSchema.default(MYNDLINK_PRESETS.reference.type),
  direction: MyndlinkDirectionSchema.default(MYNDLINK_PRESETS.reference.direction),
})

const MyndlinkAttributesHierarchySchema = MyndlinkAttributesBaseSchema.extend({
  kind: z.literal(MYNDLINK_PRESETS.hierarchy.kind).default(MYNDLINK_PRESETS.hierarchy.kind),
  type: z.literal(MYNDLINK_PRESETS.hierarchy.type).default(MYNDLINK_PRESETS.hierarchy.type),
  color: HexColorSchema.default(MYNDLINK_PRESETS.hierarchy.color),
  size: z.number().positive().default(MYNDLINK_PRESETS.hierarchy.size),
})

const MyndlinkAttributesPluginSchema = MyndlinkAttributesBaseSchema.extend({
  kind: z.string().min(1).default(MYNDLINK_PRESETS.fallback.kind),
  type: MyndlinkTypesSchema.default(MYNDLINK_PRESETS.fallback.type),
  direction: MyndlinkDirectionSchema.default(MYNDLINK_PRESETS.fallback.direction),
  pluginId: z.string().min(1).optional(),
})

/**
 * Routes known core kinds to their typed schemas, and unknown kinds to the
 * plugin schema. Uses a pipeline transform so that consumers get precise types
 * for 'reference' and 'hierarchy' while remaining open to plugin-registered
 * edge kinds.
 */
export const MyndlinkAttributesSchema = z
  .union([
    MyndlinkAttributesReferenceSchema,
    MyndlinkAttributesHierarchySchema,
    MyndlinkAttributesPluginSchema,
  ])
  .prefault({ kind: MYNDLINK_PRESETS.fallback.kind })

export const MyndlinkSchema = SerializedEdgeSchema.extend({
  key: MyndlinkKeySchema.default(createId.myndlink),
  attributes: MyndlinkAttributesSchema,
  undirected: z.literal(false).default(false),
})

const transientOmit = { type: true } satisfies Record<MyndlinkTransientKeys, true>

export const PersistableMyndlinkAttributesSchema = z
  .union([
    MyndlinkAttributesReferenceSchema.omit(transientOmit),
    MyndlinkAttributesHierarchySchema.omit(transientOmit),
    MyndlinkAttributesPluginSchema.omit(transientOmit),
  ])
  .prefault({ kind: MYNDLINK_PRESETS.fallback.kind })

export const PersistableMyndlinkSchema = MyndlinkSchema.extend({
  attributes: PersistableMyndlinkAttributesSchema,
})
