import { SerializedNodeSchema } from '../../lib/graphology/schemas'
import { HexColorSchema, NodeDisplayDataSchema } from '../../lib/sigma/schemas'
import { createId } from '../../utils/idUtils'
import { json } from '../../utils/zod/json'
import { z } from 'zod'
import type { MyndletTransientKeys } from './types'
import { MYNDLET_PRESETS } from './defaults'
import type { Point } from 'web-tree-sitter'

export const PointSchema = z.object({
  row: z.number().int().nonnegative(),
  column: z.number().int().nonnegative(),
}) satisfies z.ZodType<Point>

export const FilePositionSchema = z.object({
  start: PointSchema,
  end: PointSchema,
  startIndex: z.number().int().nonnegative(),
  endIndex: z.number().int().nonnegative(),
})

export const BuiltinMyndletKindSchema = z.enum(['folder', 'file', 'unknown'])

export const MyndletKindSchema = z.string().min(1)

export const BuiltinMyndletTypeSchema = z.enum(['glyph', 'dom', 'invisible', 'point', 'scribble'])

export const MyndletTypeSchema = BuiltinMyndletTypeSchema.or(z.string().min(1))

export const MyndletKeySchema = z.string().min(1)

export const MyndletExtSchema = z.record(z.string(), json())

export const MyndletViewsAttributesSchema = NodeDisplayDataSchema.extend({
  kind: MyndletKindSchema,
  type: MyndletTypeSchema.default(MYNDLET_PRESETS.fallback.type), // Transient: derived from kind + session state (expanded/previewed). Never author directly.
  x: z.number().default(0),
  y: z.number().default(0),
  width: z.number().positive().optional(),
  height: z.number().positive().optional(),
  size: z.number().positive().default(MYNDLET_PRESETS.fallback.size),
  color: HexColorSchema.default(MYNDLET_PRESETS.fallback.color),
  path: z.string().optional(),
  modifiedAt: z.number().optional(), // epoch time in milliseconds
  image: z.string().min(1).default(MYNDLET_PRESETS.fallback.image),
  ext: z.record(z.string(), MyndletExtSchema).optional(), // ext[pluginId] = any json-ish blob
  extKinds: z.array(z.string().nullable()).optional(), // Transient: injected by preview/plugin layers at runtime. Never persisted.
  depth: z.number().optional(),
  isCenter: z.boolean().optional(),
})

export const MyndletStatesAttributesSchema = z.object({
  isLabelEditing: z.boolean().optional(),
  labelEditingCursor: z.number().int().nonnegative().nullable().optional(),
  labelEditingCaretVisible: z.boolean().optional(),
  labelEditingSelectionStart: z.number().int().nonnegative().nullable().optional(),
  labelEditingSelectionEnd: z.number().int().nonnegative().nullable().optional(),
  filePosition: FilePositionSchema.optional(),
  locked: z.boolean().optional(),
})

export const MyndletAdapterAttributesSchema = z.object({
  adapterId: z.string().min(1).optional(),
})

// Lazy-load attributes for hierarchical loading
export const MyndletLazyLoadAttributesSchema = z.object({
  fsLoaded: z.boolean().default(true), // Whether children have been loaded from filesystem
  childCount: z.number().int().nonnegative().optional(), // Number of children (for unloaded folders)
})

const MyndletAttributesBaseSchema = MyndletViewsAttributesSchema.extend({
  ...MyndletStatesAttributesSchema.shape,
  ...MyndletAdapterAttributesSchema.shape,
  ...MyndletLazyLoadAttributesSchema.shape,
})

const MyndletAttributesFolderSchema = MyndletAttributesBaseSchema.extend({
  kind: z.literal(MYNDLET_PRESETS.folder.kind).default(MYNDLET_PRESETS.folder.kind),
  color: HexColorSchema.default(MYNDLET_PRESETS.folder.color),
  size: z.number().positive().default(MYNDLET_PRESETS.folder.size),
  image: z.string().min(1).default(MYNDLET_PRESETS.folder.image),
})

const MyndletAttributesFileSchema = MyndletAttributesBaseSchema.extend({
  kind: z.literal(MYNDLET_PRESETS.file.kind).default(MYNDLET_PRESETS.file.kind),
  color: HexColorSchema.default(MYNDLET_PRESETS.file.color),
  size: z.number().positive().default(MYNDLET_PRESETS.file.size),
  image: z.string().min(1).default(MYNDLET_PRESETS.file.image),
})

const MyndletAttributesUnknownSchema = MyndletAttributesBaseSchema.extend({
  kind: z.literal(MYNDLET_PRESETS.unknown.kind).default(MYNDLET_PRESETS.unknown.kind),
  color: HexColorSchema.default(MYNDLET_PRESETS.unknown.color),
  size: z.number().positive().default(MYNDLET_PRESETS.unknown.size),
  image: z.string().min(1).default(MYNDLET_PRESETS.unknown.image),
})

const MyndletAttributesCustomSchema = MyndletAttributesBaseSchema.extend({
  kind: z.string().min(1).default(MYNDLET_PRESETS.fallback.kind),
  color: HexColorSchema.default(MYNDLET_PRESETS.fallback.color),
  size: z.number().positive().default(MYNDLET_PRESETS.fallback.size),
  image: z.string().min(1).default(MYNDLET_PRESETS.fallback.image),
})

export const MyndletAttributesPresetSchema = z
  .discriminatedUnion('kind', [
    MyndletAttributesFolderSchema,
    MyndletAttributesFileSchema,
    MyndletAttributesUnknownSchema,
  ])
  .prefault({ kind: MYNDLET_PRESETS.fallback.kind })

export const MyndletAttributesSchema = z
  .union([MyndletAttributesPresetSchema, MyndletAttributesCustomSchema])
  .prefault({ kind: MYNDLET_PRESETS.fallback.kind })

export const MyndletSchema = SerializedNodeSchema.extend({
  key: MyndletKeySchema.default(createId.myndlet),
  attributes: MyndletAttributesSchema,
})

const transientOmit = {
  x: true,
  y: true,
  type: true,
  image: true,
  extKinds: true,
  isLabelEditing: true,
  labelEditingCursor: true,
  labelEditingCaretVisible: true,
  labelEditingSelectionStart: true,
  labelEditingSelectionEnd: true,
  filePosition: true,
  locked: true,
  depth: true,
  isCenter: true,
  highlighted: true,
  hidden: true,
  fsLoaded: true,
  childCount: true,
} satisfies Record<MyndletTransientKeys, true>

const $transientOmit = transientOmit as Record<keyof typeof transientOmit, true>

const PersistableMyndletAttributesPresetSchema = z
  .discriminatedUnion('kind', [
    MyndletAttributesFolderSchema.omit($transientOmit),
    MyndletAttributesFileSchema.omit($transientOmit),
    MyndletAttributesUnknownSchema.omit($transientOmit),
  ])
  .prefault({ kind: MYNDLET_PRESETS.fallback.kind })

export const PersistableMyndletAttributesSchema = z
  .union([
    PersistableMyndletAttributesPresetSchema,
    MyndletAttributesCustomSchema.omit($transientOmit),
  ])
  .prefault({ kind: MYNDLET_PRESETS.fallback.kind })

export const PersistableMyndletSchema = MyndletSchema.extend({
  attributes: PersistableMyndletAttributesSchema,
})
export { HexColorSchema }
