import type { BuiltinMyndletKind } from './types'

const GLYPH_ASSET_BASE_PATH = 'material-icons'

type MyndletSettingsEntry = {
  kind: string
  type: string
  color: string
  image: string
  size: number
}

type MyndletSettings = Record<BuiltinMyndletKind | 'fallback', MyndletSettingsEntry>

const iconPath = <T extends string>(filename: T) => `${GLYPH_ASSET_BASE_PATH}/${filename}` as const

export const MYNDLET_PRESETS = {
  folder: {
    kind: 'folder',
    type: 'glyph',
    color: '#FBC02D',
    image: iconPath('folder.svg'),
    size: 24,
  },
  file: {
    kind: 'file',
    type: 'glyph',
    color: '#90A4AE',
    image: iconPath('file.svg'),
    size: 20,
  },
  unknown: {
    kind: 'unknown',
    type: 'glyph',
    color: '#9e9e9e',
    image: iconPath('help.svg'),
    size: 12,
  },
  fallback: {
    kind: 'unknown',
    type: 'glyph',
    color: '#9e9e9e',
    image: iconPath('help.svg'),
    size: 12,
  },
} as const satisfies MyndletSettings

const isPresetKind = (kind: string | null): kind is BuiltinMyndletKind =>
  Boolean(kind && kind in MYNDLET_PRESETS && kind !== 'fallback')

/**
 * Get default attributes for a myndlet node, including required runtime attributes.
 * Includes x, y positions (default 0), and lazy-load attributes (fsLoaded, childCount).
 */
export const getMyndletDefaults = (kind: string | null) => {
  const base = {
    x: 0,
    y: 0,
    fsLoaded: true,
  }
  if (isPresetKind(kind)) return { ...MYNDLET_PRESETS[kind], ...base }
  return {
    ...MYNDLET_PRESETS.fallback,
    ...base,
    kind: kind ?? MYNDLET_PRESETS.fallback.kind,
  }
}
