import type { SerializedEdge, SerializedGraph, SerializedNode } from 'graphology-types'
import { z } from 'zod'

export const SerializedNodeSchema = z.object({
  key: z.string().min(1),
  attributes: z.record(z.string(), z.any()).optional(),
}) satisfies z.ZodType<SerializedNode>

export const SerializedEdgeSchema = z.object({
  key: z.string().optional(),
  source: z.string().min(1),
  target: z.string().min(1),
  attributes: z.record(z.string(), z.any()).optional(),
  undirected: z.boolean().optional(),
}) satisfies z.ZodType<SerializedEdge>

export const SerializedGraphSchema = z.object({
  nodes: z.array(SerializedNodeSchema),
  edges: z.array(SerializedEdgeSchema),
  attributes: z.record(z.string(), z.any()),
  options: z.object({
    type: z.enum(['directed', 'undirected', 'mixed']).optional(),
    allowSelfLoops: z.boolean().optional(),
    multi: z.boolean().optional(),
  }),
}) satisfies z.ZodType<SerializedGraph>
