import type { GraphAPI, DomNodeInput, Node as TreeSitterNode, SelectionAPI } from '@myndra/plugin-sdk'
import type {
  Myndlet,
  MyndletAttributes,
  Myndlink,
  MyndlinkAttributes,
  FilePosition,
} from '@myndra/plugin-sdk/schemas'
import { MyndletAttributesSchema } from '@myndra/plugin-sdk/schemas'
import { createId } from '@myndra/plugin-sdk/schemas'

type EdgeRecord = {
  source: string
  target: string
  attributes: MyndlinkAttributes
}

export type SessionGraphPayload = {
  nodes: Array<{ key: string; attributes: MyndletAttributes }>
  edges: Array<{ key: string; source: string; target: string; attributes: MyndlinkAttributes }>
}

const filePositionFromNode = (node: TreeSitterNode): FilePosition => ({
  start: { row: node.startPosition.row, column: node.startPosition.column },
  end: { row: node.endPosition.row, column: node.endPosition.column },
  startIndex: node.startIndex,
  endIndex: node.endIndex,
})

const stableHash = (value: string): string => {
  let hash = 2166136261
  for (let i = 0; i < value.length; i += 1) {
    hash ^= value.charCodeAt(i)
    hash = Math.imul(hash, 16777619)
  }
  return (hash >>> 0).toString(36)
}

const extractStableIdFromExt = (ext: unknown): string | null => {
  if (!ext || typeof ext !== 'object' || Array.isArray(ext)) return null
  const record = ext as Record<string, unknown>
  for (const value of Object.values(record)) {
    if (!value || typeof value !== 'object' || Array.isArray(value)) continue
    const valueRecord = value as Record<string, unknown>
    const stableId = typeof valueRecord.stableId === 'string' ? valueRecord.stableId : null
    const deterministicId =
      typeof valueRecord.deterministicId === 'string' ? valueRecord.deterministicId : null
    const explicit = stableId ?? deterministicId
    if (explicit && explicit.trim()) {
      return explicit
    }
  }
  return null
}

const resolveStableSeed = (
  attrs: Partial<MyndletAttributes>,
  filePosition?: FilePosition,
  scopeKey?: string | null,
): string | null => {
  const explicit = extractStableIdFromExt(attrs.ext)
  if (explicit) {
    return `ext:${explicit}`
  }
  const scope = scopeKey ? `scope:${scopeKey}|` : ''

  const position = filePosition ?? attrs.filePosition

  if (position) {
    return `${scope}pos:${position.startIndex}:${position.endIndex}|kind:${attrs.kind}|label:${attrs.label}`
  }
  if (attrs.path && attrs.label) {
    return `${scope}path:${attrs.path}|kind:${attrs.kind}|label:${attrs.label}`
  }
  if (attrs.label && attrs.kind) {
    return `${scope}label:${attrs.label}|kind:${attrs.kind}`
  }
  return null
}

const buildDeterministicNodeKey = (
  attrs: Partial<MyndletAttributes>,
  filePosition?: FilePosition,
  scopeKey?: string | null,
): string | null => {
  const seed = resolveStableSeed(attrs, filePosition, scopeKey)
  if (!seed) return null
  return `det_${stableHash(seed)}`
}

const createSelectionStub = (): SelectionAPI => ({
  getSelectedNodes: () => [],
  setSelectedNodes: () => {},
  getHoveredNode: () => null,
})

export const createSessionGraphCollector = (options: { scopeKey?: string } = {}) => {
  const nodes = new Map<string, MyndletAttributes>()
  const filePositions = new Map<string, FilePosition>()
  const edges = new Map<string, EdgeRecord>()
  const childrenIndex = new Map<string, Set<string>>()
  const parentIndex = new Map<string, string>()

  const addHierarchyChild = (source: string, target: string) => {
    const children = childrenIndex.get(source) ?? new Set<string>()
    children.add(target)
    childrenIndex.set(source, children)
    parentIndex.set(target, source)
  }

  const removeHierarchyChild = (source: string, target: string) => {
    const children = childrenIndex.get(source)
    if (!children) return
    children.delete(target)
    if (children.size === 0) childrenIndex.delete(source)
    if (parentIndex.get(target) === source) {
      parentIndex.delete(target)
    }
  }

  const graph: GraphAPI = {
    getNode: (key) => {
      const attributes = nodes.get(key)
      if (!attributes) return null
      const node: Myndlet = { key, attributes }
      node.attributes.label = node.attributes.label ?? null
      return node
    },
    getNodeAttribute: <T = unknown>(key: string, attribute: string): T | undefined => {
      const attributes = nodes.get(key)
      if (!attributes) return undefined
      return attributes[attribute as keyof MyndletAttributes] as T
    },
    getFilePosition: (key) => filePositions.get(key) ?? null,
    getNodeEdges: (nodeKey) => {
      const results: Myndlink[] = []
      edges.forEach((edge, edgeKey) => {
        if (edge.source === nodeKey || edge.target === nodeKey) {
          results.push({
            key: edgeKey,
            source: edge.source,
            target: edge.target,
            attributes: edge.attributes,
            undirected: false,
          })
        }
      })
      return results
    },
    hasNode: (key) => nodes.has(key),
    getChildren: (nodeKey) => Array.from(childrenIndex.get(nodeKey) ?? []),
    getParent: (nodeKey) => parentIndex.get(nodeKey) ?? null,
    findNodes: (predicate) => {
      const results: Myndlet[] = []
      nodes.forEach((attributes, key) => {
        const node: Myndlet = { key, attributes }
        node.attributes.label = node.attributes.label ?? null
        if (predicate(node)) results.push(node)
      })
      return results
    },
    batch: (fn) => fn(),
    durable: {
      updateNode: (key: string, patch: Partial<MyndletAttributes>) => {
        if ('filePosition' in patch) {
          if (patch.filePosition) {
            filePositions.set(key, patch.filePosition)
          } else {
            filePositions.delete(key)
          }
        }
        const { filePosition: _filePosition, ...rest } = patch
        const existing = nodes.get(key) ?? (rest as MyndletAttributes)
        nodes.set(key, { ...existing, ...rest })
      },
      addNode: (attributes: MyndletAttributes): string => {
        const position = attributes.filePosition ?? undefined
        const key =
          buildDeterministicNodeKey(attributes, position, options.scopeKey) ?? createId.myndlet()
        const { filePosition: _filePosition, ...rest } = attributes
        nodes.set(key, { ...rest })
        if (position) filePositions.set(key, position)
        return key
      },
      addDomNode: (input: DomNodeInput): string => {
        const baseAttributes = { ...(input.attributes ?? {}) }
        const position = input.position
        const x =
          typeof position?.x === 'number'
            ? position.x
            : typeof baseAttributes.x === 'number'
              ? baseAttributes.x
              : 0
        const y =
          typeof position?.y === 'number'
            ? position.y
            : typeof baseAttributes.y === 'number'
              ? baseAttributes.y
              : 0
        const size =
          typeof baseAttributes.size === 'number' && baseAttributes.size > 0
            ? baseAttributes.size
            : 0.0001
        const normalizeFocus = (value: unknown): string | null => {
          if (typeof value !== 'string') return null
          const trimmed = value.trim()
          return trimmed.length > 0 ? trimmed : null
        }
        const domFocusNodeKey = normalizeFocus(input.domFocusNodeKey)

        const rawAttributes = {
          ...baseAttributes,
          kind: input.kind,
          type: 'dom',
          hidden: true,
          size,
          x,
          y,
          domFocusNodeKey,
        }
        const finalAttributes = MyndletAttributesSchema.parse(rawAttributes)
        const key =
          buildDeterministicNodeKey(
            finalAttributes,
            finalAttributes.filePosition,
            options.scopeKey,
          ) ?? createId.myndlet()
        const { filePosition: _filePosition, ...rest } = finalAttributes
        nodes.set(key, rest)
        if (finalAttributes.filePosition) filePositions.set(key, finalAttributes.filePosition)
        return key
      },
      removeNode: (key: string) => {
        nodes.delete(key)
        filePositions.delete(key)
        parentIndex.delete(key)
        Array.from(edges.entries()).forEach(([edgeKey, edge]) => {
          if (edge.source === key || edge.target === key) {
            edges.delete(edgeKey)
            if (edge.attributes.kind === 'hierarchy') {
              removeHierarchyChild(edge.source, edge.target)
            }
          }
        })
      },
      addReferenceLink: (source: string, target: string, attributes?: Partial<MyndlinkAttributes>): string => {
        const key = createId.myndlink()
        edges.set(key, { source, target, attributes: attributes as MyndlinkAttributes })
        return key
      },
      addHierarchyLink: (source: string, target: string, attributes?: Partial<MyndlinkAttributes>): string => {
        const key = createId.hierarchicalMyndlink(source, target)
        edges.set(key, { source, target, attributes: attributes as MyndlinkAttributes })
        addHierarchyChild(source, target)
        return key
      },
      removeLink: (edgeKey: string) => {
        const edge = edges.get(edgeKey)
        if (!edge) return
        if (edge.attributes.kind === 'hierarchy') {
          removeHierarchyChild(edge.source, edge.target)
        }
        edges.delete(edgeKey)
      },
    },
    derived: {
      addTreeSitterNode: (treeSitterNode: TreeSitterNode, attributes: Omit<MyndletAttributes, 'filePosition'>): string => {
        const filePosition = filePositionFromNode(treeSitterNode)
        const key =
          buildDeterministicNodeKey(attributes, filePosition, options.scopeKey) ?? createId.myndlet()
        nodes.set(key, { ...attributes } as MyndletAttributes)
        filePositions.set(key, filePosition)
        return key
      },
      setFilePosition: (key: string, position: FilePosition) => {
        if (!nodes.has(key)) return
        filePositions.set(key, position)
      },
      syncFilePositions: (positions: Map<string, FilePosition>) => {
        positions.forEach((position, key) => {
          if (!nodes.has(key)) return
          filePositions.set(key, position)
        })
      },
    },
    selection: createSelectionStub(),
    session: {
      inject: () => {},
      clear: () => {},
    },
  }

  const getPayload = (): SessionGraphPayload => ({
    nodes: Array.from(nodes.entries()).map(([key, attributes]) => ({ key, attributes })),
    edges: Array.from(edges.entries()).map(([key, edge]) => ({
      key,
      source: edge.source,
      target: edge.target,
      attributes: edge.attributes,
    })),
  })

  return { graph, getPayload }
}
