import semver from 'semver'

export interface CompatibilityResult {
  compatible: boolean
  reason?: string
}

/**
 * Check whether the host engine version satisfies a plugin's declared engine range.
 *
 * - If `manifestEngine` is undefined the plugin declares no constraint → compatible.
 * - If `manifestEngine` is not a valid semver range → incompatible with reason.
 * - Otherwise delegates to `semver.satisfies`.
 */
export function checkEngineCompatibility(
  manifestEngine: string | undefined,
  hostVersion: string,
): CompatibilityResult {
  if (manifestEngine === undefined) {
    return { compatible: true }
  }

  const range = semver.validRange(manifestEngine)
  if (range === null) {
    return {
      compatible: false,
      reason: `Invalid engine range "${manifestEngine}"`,
    }
  }

  // Coerce the host version so pre-release tags like "0.0.0-dev" still match
  const coerced = semver.coerce(hostVersion)
  const version = coerced ? coerced.version : hostVersion

  if (!semver.satisfies(version, range)) {
    return {
      compatible: false,
      reason: `Host version "${hostVersion}" does not satisfy engine range "${manifestEngine}"`,
    }
  }

  return { compatible: true }
}
