import type { Coordinates, DisplayData, EdgeDisplayData, NodeDisplayData } from 'sigma/types'
import z from 'zod'

export const HexColorSchema = z.string().regex(/^#([0-9a-f]{3}|[0-9a-f]{6})$/i)

export const CoordinatesSchema = z.object({
  x: z.number(),
  y: z.number(),
}) satisfies z.ZodType<Coordinates>

export const DisplayDataSchema = z
  .object({
    label: z.string().nullable(),
    size: z.number().positive(),
    color: HexColorSchema,
    hidden: z.boolean(),
    forceLabel: z.boolean(),
    zIndex: z.number().int().nonnegative(),
    type: z.string().min(1),
  })
  .partial() satisfies z.ZodType<Partial<DisplayData>>

export const NodeDisplayDataSchema = CoordinatesSchema.extend(DisplayDataSchema.shape).extend({
  highlighted: z.boolean().optional(),
}) satisfies z.ZodType<Coordinates & Partial<NodeDisplayData>>

export const EdgeDisplayDataSchema = DisplayDataSchema satisfies z.ZodType<Partial<EdgeDisplayData>>
