import type { MyndlinkCoreKind, MyndlinkDirection } from './types'

type MyndlinkSettings = Record<
  MyndlinkCoreKind | 'fallback',
  {
    kind: string
    type: string
    color: string
    size: number
    label: string | null
    direction: MyndlinkDirection
  }
>

export const MYNDLINK_PRESETS = {
  hierarchy: {
    kind: 'hierarchy',
    type: 'arrow',
    color: '#b8b8b8',
    size: 1,
    label: null,
    direction: 'outgoing',
  },
  reference: {
    kind: 'reference',
    type: 'arrow',
    color: '#666666',
    size: 1,
    label: null,
    direction: 'bidirectional',
  },
  fallback: {
    kind: 'reference',
    type: 'line',
    color: '#666666',
    size: 1,
    label: null,
    direction: 'bidirectional',
  },
} as const satisfies MyndlinkSettings

const isPresetKind = (kind: string | undefined): kind is MyndlinkCoreKind =>
  Boolean(kind && kind in MYNDLINK_PRESETS && kind !== 'fallback')

export const getMyndlinkDefaults = (kind: string | undefined) =>
  isPresetKind(kind) ? MYNDLINK_PRESETS[kind] : MYNDLINK_PRESETS.fallback
